        "Description": "Lookup of federated node label.",
        "formula": "=IF({{FederatedDataset}} = \"\", \"\", INDEX(FederatedDatasets!{{NodeLabel}}, MATCH({{FederatedDataset}}, FederatedDatasets!{{FederatedDatasetId}}, 0)))"
